     1→/**
     2→ * Classification Pipeline Orchestrator
     3→ *
     4→ * Orchestrates the complete 9-stage classification pipeline with canonical signatures:
     5→ * (email, session, result, config) => void
     6→ *
     7→ * Pipeline Stages:
     8→ * 1. Hard Assertions - Domain-based high-confidence categorization
     9→ * 2. Strong Indicators - Weighted seed scoring with diminishing returns
    10→ * 3. Rule Scoring - Hierarchical pattern matching (high/medium/low tiers)
    11→ * 4. Attribute Detection - Cross-cutting signals (urgency, domains, structural patterns)
    12→ * 5. Attribute Influence - Role-based bonuses (CORE, PRIMARY_BOOST, etc.)
    13→ * 6. Disambiguation - Pairwise conflict resolution for close scores
    14→ * 7. Multi-label Selection - Confidence-based label assignment with co-presence rules
    15→ * 8. AI Routing - Selective AI classification for uncertain cases
    16→ * 9. Final Decision - Label assignment and action determination
    17→ * 10. Audit Trail - Complete explainability trace generation
    18→ */
    19→
    20→import { EmailMessage } from '../types/email-message';
    21→import { CategoryConfiguration } from '../types/category-configuration';
    22→import { ClassificationResult } from '../types/classification-result';
    23→import { ClassificationSession } from '../types/classification-session';
    24→
    25→// Validation utilities
    26→import { validateEmailInput, validateConfigInput } from '../utils/validation';
    27→
    28→// Initialization utilities
    29→import {
    30→  createClassificationSession,
    31→  createClassificationResult,
    32→  incrementSessionSuccess,
    33→  incrementSessionError,
    34→  finalizeClassificationSession,
    35→} from '../utils/initialization';
    36→
    37→// Pipeline stages (canonical signatures)
    38→import { executeHardAssertions } from '../stages/hard-assertions';
    39→import { executeStrongIndicators } from '../stages/strong-indicators';
    40→import { executeRuleScoring } from '../stages/rule-scoring';
    41→import { executeAttributeDetection } from '../stages/attribute-detection';
    42→import { executeAttributeInfluence } from '../stages/attribute-influence';
    43→import { executeDisambiguation } from '../stages/disambiguation';
    44→import { executeMultiLabelSelection } from '../stages/multi-label-selection';
    45→import { aiRoutingStage } from '../stages/ai-routing';
    46→import { aiFeatureExtractionStage } from '../stages/ai-feature-extraction';
    47→import { aiClassificationStage } from '../stages/ai-classification';
    48→import { aiLabelFilteringStage } from '../stages/ai-label-filtering';
    49→import { actionDeterminationStage } from '../stages/action-determination';
    50→// import { generateAuditTrail } from '../stages/audit-trail'; // TODO: Wire audit trail after PipelineResults refactoring
    51→
    52→// Stage-specific config types
    53→import type { HardAssertionStageConfig } from '../stages/hard-assertions';
    54→import type { StrongIndicatorStageConfig } from '../stages/strong-indicators';
    55→import type { RuleScoringStageConfig } from '../stages/rule-scoring';
    56→import type { AttributeDetectionStageConfig } from '../stages/attribute-detection';
    57→import type { MultiLabelConfig, ConfidenceThresholds } from '../stages/types';
    58→import type { AIRoutingConfig } from '../stages/ai-routing';
    59→import type { AIFeatureExtractionConfig } from '../stages/ai-feature-extraction';
    60→import type { AIClassificationConfig } from '../stages/ai-classification';
    61→import type { AILabelFilteringConfig } from '../stages/ai-label-filtering';
    62→import type { ActionDeterminationConfig } from '../stages/action-determination';
    63→// import type { AuditTrailConfig } from '../stages/audit-trail'; // TODO: Wire audit trail after PipelineResults refactoring
    64→
    65→/**
    66→ * Pipeline stage execution order for replay functionality
    67→ */
    68→const STAGE_ORDER = [
    69→  'hard-assertions',
    70→  'strong-indicators',
    71→  'rule-scoring',
    72→  'attribute-detection',
    73→  'attribute-influence',
    74→  'disambiguation',
    75→  'multi-label-selection',
    76→  'ai-routing',
    77→  'ai-feature-extraction',
    78→  'ai-classification',
    79→  'ai-label-filtering',
    80→  'action-determination',
    81→] as const;
    82→
    83→/**
    84→ * Stage task interface for replay-from-stage support
    85→ *
    86→ * Wraps individual pipeline stage functions to enable selective execution
    87→ * based on replay parameters while maintaining minimal disruption to existing code.
    88→ */
    89→interface StageTask {
    90→  /**
    91→   * Stage identifier for replay functionality
    92→   */
    93→  name: string;
    94→
    95→  /**
    96→   * Execute the stage with canonical signature pattern
    97→   *
    98→   * @param email - Email message to process
    99→   * @param session - Classification session context
   100→   * @param result - Mutable classification result (modified in place)
   101→   * @param config - Stage-specific configuration
   102→   */
   103→  execute(
   104→    email: EmailMessage,
   105→    session: ClassificationSession,
   106→    result: ClassificationResult,
   107→    config: CategoryConfiguration
   108→  ): Promise<void>;
   109→
   110→  /**
   111→   * Determine if this stage should be skipped for replay functionality
   112→   *
   113→   * @param replayFromStage - Optional stage to start replay from
   114→   * @returns true if stage should be skipped, false to execute
   115→   */
   116→  shouldSkip(replayFromStage?: string): boolean;
   117→}
   118→
   119→/**
   120→ * Error result for batch processing when individual email fails
   121→ */
   122→export interface ClassificationErrorResult {
   123→  error: Error;
   124→  emailId: string;
   125→  processingDurationMs: number;
   126→}
   127→
   128→/**
   129→ * Classification Pipeline orchestrator
   130→ *
   131→ * Manages sequential execution of classification stages with proper context
   132→ * propagation, error handling, and performance tracking.
   133→ */
   134→export class ClassificationPipeline {
   135→  private readonly config: CategoryConfiguration;
   136→  private readonly testMode: boolean;
   137→
   138→  /**
   139→   * Initialize classification pipeline with validated configuration
   140→   *
   141→   * @param config - Complete category configuration including processingConfig
   142→   * @param testMode - If true, use timestamp-based session IDs for easier debugging
   143→   * @throws {Error} If configuration validation fails
   144→   */
   145→  constructor(config: CategoryConfiguration, testMode: boolean = false) {
   146→    // Validate processing configuration
   147→    validateConfigInput(config.processingConfig);
   148→
   149→    // Validate confidence thresholds specifically
   150→    const { confidenceThresholds } = config.processingConfig;
   151→    if (
   152→      !confidenceThresholds ||
   153→      confidenceThresholds.highConfidence < 0 ||
   154→      confidenceThresholds.mediumConfidence < 0 ||
   155→      confidenceThresholds.lowConfidence < 0 ||
   156→      confidenceThresholds.secondaryLabelMinGap < 0
   157→    ) {
   158→      throw new Error('Invalid confidence thresholds: all values must be non-negative');
   159→    }
   160→
   161→    this.config = config;
   162→    this.testMode = testMode;
   163→  }
   164→
   165→  /**
   166→   * Get configuration (for testing and future stage integration)
   167→   */
   168→  getConfig(): CategoryConfiguration {
   169→    return this.config;
   170→  }
   171→
   172→  /**
   173→   * Helper function to determine if a stage should be skipped for replay
   174→   *
   175→   * @param stageName - Name of the current stage
   176→   * @param replayFromStage - Stage to start replay from (optional)
   177→   * @returns true if stage should be skipped, false to execute
   178→   */
   179→  private shouldSkipStage(stageName: string, replayFromStage?: string): boolean {
   180→    if (!replayFromStage) return false;
   181→    const replayIndex = STAGE_ORDER.indexOf(replayFromStage as (typeof STAGE_ORDER)[number]);
   182→    const currentIndex = STAGE_ORDER.indexOf(stageName as (typeof STAGE_ORDER)[number]);
   183→    return replayIndex !== -1 && currentIndex < replayIndex;
   184→  }
   185→
   186→  /**
   187→   * Create ordered array of stage tasks for replay functionality
   188→   *
   189→   * Each stage task wraps existing stage functions with replay logic
   190→   * while preserving canonical signatures and conditional execution.
   191→   *
   192→   * @returns Array of stage tasks in execution order
   193→   */
   194→  private createStageTasks(): StageTask[] {
   195→    const stageTasks: StageTask[] = [
   196→      // Stage 1: Hard Assertions
   197→      {
   198→        name: 'hard-assertions',
   199→        execute: async (email, session, result, _config) => {
   200→          executeHardAssertions(email, session, result, this.getHardAssertionConfig());
   201→        },
   202→        shouldSkip: (replayFromStage) => this.shouldSkipStage('hard-assertions', replayFromStage),
   203→      },
   204→
   205→      // Stage 2: Strong Indicators
   206→      {
   207→        name: 'strong-indicators',
   208→        execute: async (email, session, result, _config) => {
   209→          executeStrongIndicators(email, session, result, this.getStrongIndicatorConfig());
   210→        },
   211→        shouldSkip: (replayFromStage) => this.shouldSkipStage('strong-indicators', replayFromStage),
   212→      },
   213→
   214→      // Stage 3: Rule Scoring
   215→      {
   216→        name: 'rule-scoring',
   217→        execute: async (email, session, result, _config) => {
   218→          executeRuleScoring(email, session, result, this.getRuleScoringConfig());
   219→        },
   220→        shouldSkip: (replayFromStage) => this.shouldSkipStage('rule-scoring', replayFromStage),
   221→      },
   222→
   223→      // Stage 4: Attribute Detection
   224→      {
   225→        name: 'attribute-detection',
   226→        execute: async (email, session, result, _config) => {
   227→          executeAttributeDetection(email, session, result, this.getAttributeDetectionConfig());
   228→        },
   229→        shouldSkip: (replayFromStage) => this.shouldSkipStage('attribute-detection', replayFromStage),
   230→      },
   231→
   232→      // Stage 5: Attribute Influence
   233→      {
   234→        name: 'attribute-influence',
   235→        execute: async (email, session, result, _config) => {
   236→          executeAttributeInfluence(email, session, result, this.config);
   237→        },
   238→        shouldSkip: (replayFromStage) => this.shouldSkipStage('attribute-influence', replayFromStage),
   239→      },
   240→
   241→      // Stage 6: Disambiguation
   242→      {
   243→        name: 'disambiguation',
   244→        execute: async (email, session, result, _config) => {
   245→          executeDisambiguation(email, session, result, this.config);
   246→        },
   247→        shouldSkip: (replayFromStage) => this.shouldSkipStage('disambiguation', replayFromStage),
   248→      },
   249→
   250→      // Stage 7: Multi-label Selection
   251→      {
   252→        name: 'multi-label-selection',
   253→        execute: async (email, session, result, _config) => {
   254→          executeMultiLabelSelection(
   255→            email,
   256→            session,
   257→            result,
   258→            this.getMultiLabelConfig(),
   259→            this.getConfidenceThresholds()
   260→          );
   261→        },
   262→        shouldSkip: (replayFromStage) => this.shouldSkipStage('multi-label-selection', replayFromStage),
   263→      },
   264→
   265→      // Stage 8a: AI Routing
   266→      {
   267→        name: 'ai-routing',
   268→        execute: async (email, session, result, _config) => {
   269→          aiRoutingStage(email, session, result, this.getAIRoutingConfig());
   270→        },
   271→        shouldSkip: (replayFromStage) => this.shouldSkipStage('ai-routing', replayFromStage),
   272→      },
   273→
   274→      // Stage 8b: AI Feature Extraction (conditional)
   275→      {
   276→        name: 'ai-feature-extraction',
   277→        execute: async (email, session, result, _config) => {
   278→          if (result.needsAiClassification) {
   279→            await aiFeatureExtractionStage(email, session, result, this.getAIFeatureExtractionConfig());
   280→          }
   281→        },
   282→        shouldSkip: (replayFromStage) => this.shouldSkipStage('ai-feature-extraction', replayFromStage),
   283→      },
   284→
   285→      // Stage 8c: AI Classification (conditional)
   286→      {
   287→        name: 'ai-classification',
   288→        execute: async (email, session, result, _config) => {
   289→          if (result.needsAiClassification) {
   290→            await aiClassificationStage(email, session, result, this.getAIClassificationConfig());
   291→          }
   292→        },
   293→        shouldSkip: (replayFromStage) => this.shouldSkipStage('ai-classification', replayFromStage),
   294→      },
   295→
   296→      // Stage 8d: AI Label Filtering (conditional)
   297→      {
   298→        name: 'ai-label-filtering',
   299→        execute: async (email, session, result, _config) => {
   300→          if (result.needsAiClassification) {
   301→            await aiLabelFilteringStage(email, session, result, this.getAILabelFilteringConfig());
   302→          }
   303→        },
   304→        shouldSkip: (replayFromStage) => this.shouldSkipStage('ai-label-filtering', replayFromStage),
   305→      },
   306→
   307→      // Stage 9: Action Determination (runs for ALL emails)
   308→      {
   309→        name: 'action-determination',
   310→        execute: async (email, session, result, _config) => {
   311→          await actionDeterminationStage(email, session, result, this.getActionDeterminationConfig());
   312→        },
   313→        shouldSkip: (replayFromStage) => this.shouldSkipStage('action-determination', replayFromStage),
   314→      },
   315→    ];
   316→
   317→    return stageTasks;
   318→  }
   319→
   320→  /**
   321→   * Execute classification pipeline using StageTask architecture with optional replay support
   322→   *
   323→   * Provides the foundation for true replay-from-stage functionality by iterating
   324→   * through stage tasks and selectively skipping stages based on replay parameters.
   325→   *
   326→   * @param email - Email message to classify
   327→   * @param replayFromStage - Optional stage name to start replay from
   328→   * @returns Complete classification result with selected labels
   329→   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   330→   */
   331→  async classifyWithStageTask(email: EmailMessage, replayFromStage?: string): Promise<ClassificationResult> {
   332→    const pipelineStartTime = Date.now();
   333→
   334→    try {
   335→      // Validate email input
   336→      validateEmailInput(email);
   337→
   338→      // Create classification session for single email
   339→      const session = createClassificationSession(this.config.processingConfig, 'sequential', 1, this.testMode);
   340→
   341→      // Create classification result
   342→      const result = createClassificationResult(email.id, session.id, 0);
   343→
   344→      // Get stage tasks array
   345→      const stageTasks = this.createStageTasks();
   346→
   347→      // Execute stages using StageTask architecture
   348→      for (const stageTask of stageTasks) {
   349→        // Check if this stage should be skipped for replay
   350→        if (stageTask.shouldSkip(replayFromStage)) {
   351→          // Log stage skipping only in test mode for debugging
   352→          if (this.testMode && replayFromStage) {
   353→            console.log(`Skipping stage: ${stageTask.name} (replay from: ${replayFromStage})`);
   354→          }
   355→          continue;
   356→        }
   357→
   358→        // Log stage execution only in test mode for debugging
   359→        if (this.testMode) {
   360→          console.log(`Executing stage: ${stageTask.name}`);
   361→        }
   362→
   363→        // Execute the stage (maintains canonical signature pattern)
   364→        try {
   365→          await stageTask.execute(email, session, result, this.config);
   366→        } catch (error) {
   367→          throw new Error(
   368→            `Stage '${stageTask.name}' failed: ${error instanceof Error ? error.message : String(error)}`
   369→          );
   370→        }
   371→      }
   372→
   373→      // Mark session as successful
   374→      incrementSessionSuccess(session);
   375→      finalizeClassificationSession(session);
   376→
   377→      // Update final processing time
   378→      result.processingDurationMs = Date.now() - pipelineStartTime;
   379→      result.processedAt = new Date();
   380→
   381→      return result;
   382→    } catch (error) {
   383→      // Capture error with processing time
   384→      const pipelineEndTime = Date.now();
   385→      throw new Error(
   386→        `Classification pipeline failed for email ${email.id} after ${pipelineEndTime - pipelineStartTime}ms: ${error instanceof Error ? error.message : String(error)}`
   387→      );
   388→    }
   389→  }
   390→
   391→  /**
   392→   * Execute classification pipeline using provided session (for batch processing)
   393→   *
   394→   * Uses an externally-created session to enable multiple emails to share the same
   395→   * sessionId. This is essential for batch processing where all emails should be
   396→   * grouped under one session for traceability.
   397→   *
   398→   * @param email - Email message to classify
   399→   * @param session - Existing classification session to use
   400→   * @param batchPosition - Position of email in batch (for result metadata)
   401→   * @param replayFromStage - Optional stage name to start replay from
   402→   * @returns Complete classification result with selected labels
   403→   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   404→   */
   405→  async classifyWithSession(
   406→    email: EmailMessage,
   407→    session: ClassificationSession,
   408→    batchPosition: number = 0,
   409→    replayFromStage?: string
   410→  ): Promise<ClassificationResult> {
   411→    const pipelineStartTime = Date.now();
   412→
   413→    try {
   414→      // Validate email input
   415→      validateEmailInput(email);
   416→
   417→      // Create classification result using provided session
   418→      const result = createClassificationResult(email.id, session.id, batchPosition);
   419→
   420→      // Get stage tasks array
   421→      const stageTasks = this.createStageTasks();
   422→
   423→      // Execute stages using StageTask architecture
   424→      for (const stageTask of stageTasks) {
   425→        // Check if this stage should be skipped for replay
   426→        if (stageTask.shouldSkip(replayFromStage)) {
   427→          // Log stage skipping only in test mode for debugging
   428→          if (this.testMode && replayFromStage) {
   429→            console.log(`Skipping stage: ${stageTask.name} (replay from: ${replayFromStage})`);
   430→          }
   431→          continue;
   432→        }
   433→
   434→        // Log stage execution only in test mode for debugging
   435→        if (this.testMode) {
   436→          console.log(`Executing stage: ${stageTask.name}`);
   437→        }
   438→
   439→        // Execute the stage (maintains canonical signature pattern)
   440→        try {
   441→          await stageTask.execute(email, session, result, this.config);
   442→        } catch (error) {
   443→          throw new Error(
   444→            `Stage '${stageTask.name}' failed: ${error instanceof Error ? error.message : String(error)}`
   445→          );
   446→        }
   447→      }
   448→
   449→      // Update final processing time
   450→      result.processingDurationMs = Date.now() - pipelineStartTime;
   451→      result.processedAt = new Date();
   452→
   453→      return result;
   454→    } catch (error) {
   455→      // Capture error with processing time
   456→      const pipelineEndTime = Date.now();
   457→      throw new Error(
   458→        `Classification pipeline failed for email ${email.id} after ${pipelineEndTime - pipelineStartTime}ms: ${error instanceof Error ? error.message : String(error)}`
   459→      );
   460→    }
   461→  }
   462→
   463→  /**
   464→   * Extract configuration for hard assertions stage
   465→   */
   466→  private getHardAssertionConfig(): HardAssertionStageConfig {
   467→    return {
   468→      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
   469→      categorySignals: this.config.processingConfig.categorySignals as never, // TODO: Fix type mismatch in Phase 3.6
   470→      domainLookup: {}, // TODO: Implement domain resolution in Phase 3.6
   471→    };
   472→  }
   473→
   474→  /**
   475→   * Extract configuration for strong indicators stage
   476→   */
   477→  private getStrongIndicatorConfig(): StrongIndicatorStageConfig {
   478→    return {
   479→      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
   480→      categorySignals: this.config.processingConfig.categorySignals as never, // TODO: Fix type mismatch in Phase 3.6
   481→      domainLookup: {}, // TODO: Implement domain resolution in Phase 3.6
   482→      strongIndicatorBaseWeight: 10, // TODO: Extract from config in Phase 3.6
   483→      diminishingReturnsFactor: 0.5, // TODO: Extract from config in Phase 3.6
   484→    };
   485→  }
   486→
   487→  /**
   488→   * Extract configuration for rule scoring stage
   489→   */
   490→  private getRuleScoringConfig(): RuleScoringStageConfig {
   491→    return {
   492→      topLevelCategories: this.config.processingConfig.topLevelCategories,
   493→      settings: this.config.processingConfig.settings.ruleScoring,
   494→      tuningParameters: {
   495→        K_high: 5, // TODO: Extract from config in Phase 3.6
   496→        K_medium: 10, // TODO: Extract from config in Phase 3.6
   497→        K_low: 15, // TODO: Extract from config in Phase 3.6
   498→        M_medium: 0.7, // TODO: Extract from config in Phase 3.6
   499→        M_low: 0.3, // TODO: Extract from config in Phase 3.6
   500→        TAIL_DAMPEN: 0.5, // TODO: Extract from config in Phase 3.6
   501→        TAIL_RATIO_CAP: 0.25, // TODO: Extract from config in Phase 3.6
   502→      },
   503→    };
   504→  }
   505→
   506→  /**
   507→   * Extract configuration for attribute detection stage
   508→   */
   509→  private getAttributeDetectionConfig(): AttributeDetectionStageConfig {
   510→    return {
   511→      attributes: this.config.processingConfig.attributes,
   512→      settings: {
   513→        attributeProcessing: this.config.processingConfig.settings.attributeProcessing,
   514→      },
   515→      performanceCache: {}, // Optional performance cache for domain lookups
   516→    };
   517→  }
   518→
   519→  /**
   520→   * Extract configuration for multi-label selection stage
   521→   */
   522→  private getMultiLabelConfig(): MultiLabelConfig {
   523→    return {
   524→      maxLabels: this.config.processingConfig.multiLabelPolicy.maxTopLevelLabels,
   525→      minSecondaryConfidence: this.config.processingConfig.multiLabelPolicy.minConfidenceForAdditional,
   526→      allowedCombinations: [], // TODO: Extract from multiLabelPolicy in Phase 3.6
   527→    };
   528→  }
   529→
   530→  /**
   531→   * Get confidence thresholds
   532→   */
   533→  private getConfidenceThresholds(): ConfidenceThresholds {
   534→    return this.config.processingConfig.confidenceThresholds;
   535→  }
   536→
   537→  /**
   538→   * Extract configuration for AI routing stage
   539→   */
   540→  private getAIRoutingConfig(): AIRoutingConfig {
   541→    return {
   542→      settings: {
   543→        aiRouting: this.config.processingConfig.settings.aiRouting,
   544→      },
   545→      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
   546→    };
   547→  }
   548→
   549→  /**
   550→   * Extract configuration for AI feature extraction stage
   551→   */
   552→  private getAIFeatureExtractionConfig(): AIFeatureExtractionConfig {
   553→    const openaiApiKey = process.env.OPENAI_API_KEY || '';
   554→    if (!openaiApiKey) {
   555→      throw new Error('OPENAI_API_KEY environment variable is required for AI feature extraction');
   556→    }
   557→
   558→    return {
   559→      openai: {
   560→        apiKey: openaiApiKey,
   561→        model: 'gpt-4o-mini',
   562→        temperature: 0.0,
   563→        responseFormat: 'json_schema',
   564→      },
   565→      prompts: this.config.processingConfig.aiPrompts.featureExtraction,
   566→      featureExtractionSchema: {
   567→        name: 'email_feature_extraction',
   568→        description: 'Extract semantic features from email content',
   569→        schema: this.config.processingConfig.featureExtractionSchema as unknown as Record<string, unknown>,
   570→        strict: true,
   571→      },
   572→      retryPolicy: {
   573→        maxRetries: 3,
   574→        backoffMs: 1000,
   575→      },
   576→    };
   577→  }
   578→
   579→  /**
   580→   * Extract configuration for AI classification stage
   581→   */
   582→  private getAIClassificationConfig(): AIClassificationConfig {
   583→    const openaiApiKey = process.env.OPENAI_API_KEY || '';
   584→    if (!openaiApiKey) {
   585→      throw new Error('OPENAI_API_KEY environment variable is required for AI classification');
   586→    }
   587→
   588→    return {
   589→      openai: {
   590→        apiKey: openaiApiKey,
   591→        model: 'gpt-4o-mini',
   592→        temperature: 0.0,
   593→        responseFormat: 'json_schema',
   594→      },
   595→      prompts: this.config.processingConfig.aiPrompts.finalClassification,
   596→      classificationSchema: {
   597→        name: 'email_classification',
   598→        description: 'Classify email into categories',
   599→        schema: {
   600→          type: 'object',
   601→          properties: {
